      const cameraRight = new THREE.Vector3(1, 0, 0).applyQuaternion(camera.quaternion);
      const sampledScreenRight = sampleX
        ? horizontalCameraVector(
            new THREE.Vector3(
              sampleX.point.xMm - origin.point.xMm,
              0,
              sampleX.point.yMm - origin.point.yMm,
