        />
      </ErrorBoundary>
    );
  return viewerMode === 'orbit_3d' ? (
    <Viewport
      wsConnected={wsOn ?? false}
      onPersistViewpointField={onPersistViewpointField}
      onSemanticCommand={onSemanticCommand}
      lensMode={lensMode}
      activePlanTool={activePlanTool}
