      activePlanViewId={activePlanViewId}
      onSemanticCommand={onSemanticCommand}
      lensMode={lensMode}
      activePlanTool={activePlanTool}
      onActivePlanToolChange={onActivePlanToolChange}
      snapSettings={snapSettings}
    />
  );
}

