if (await tab.count()) await tab.first().click();
await page.getByTestId('orbit-3d-viewport').waitFor({ timeout: 15000 });
await page.waitForTimeout(1200);
const vp = page.getByTestId('orbit-3d-viewport');
const box = await vp.boundingBox();
if (!box) throw new Error('no viewport');
await page.getByTestId('ribbon-command-wall').click();
await page.waitForTimeout(300);
const p1 = { x: box.x + box.width * 0.80, y: box.y + box.height * 0.72 };
const p2 = { x: box.x + box.width * 0.92, y: box.y + box.height * 0.72 };
const p3 = { x: box.x + box.width * 0.92, y: box.y + box.height * 0.62 };
await page.mouse.move(p1.x, p1.y);
await page.mouse.down();
await page.mouse.move(p2.x, p2.y, { steps: 15 });
await page.mouse.up();
await page.waitForTimeout(900);
await page.mouse.move(p3.x, p3.y, { steps: 12 });
